// src/pages/LabourDashboard.jsx

import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function LabourDashboard() {

  const user = JSON.parse(localStorage.getItem("user") || "{}");

  const [requests, setRequests] = useState([]);
  const [price, setPrice] = useState({});

  useEffect(() => {
    getRequests();
  }, []);

  const getRequests = async () => {
    try {
      const res = await axios.get(
        `http://localhost:5000/api/request/labour/${user._id}`
      );
      setRequests(res.data);
    } catch (err) {
      console.log(err);
    }
  };

  const respondRequest = async (id, action) => {
    try {
      await axios.put(
        `http://localhost:5000/api/request/labour-response/${id}`,
        {
          price: price[id] || 0,
          action
        }
      );
      getRequests();
    } catch (err) {
      console.log(err);
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>

        <h2 style={styles.heading}>Incoming Requests</h2>

        {requests.length === 0 && (
          <p style={styles.empty}>No requests found</p>
        )}

        {requests.map((req) => (
          <div key={req._id} style={styles.card}>

            {/* LEFT ACCENT BAR */}
            <div style={styles.accent}></div>

            {/* HEADER */}
            <div style={styles.header}>
              <h3 style={styles.name}>{req.customerName}</h3>
              <span style={styles.badge}>{req.status}</span>
            </div>

            {/* DETAILS */}
            <div style={styles.details}>
              <p><b>Work:</b> {req.workType}</p>
              <p><b>Location:</b> {req.location}</p>
              <p><b>Date:</b> {req.date}</p>
              <p><b>Decision:</b> {req.customerDecision}</p>
            </div>

            {/* PRICE */}
            <input
              type="number"
              placeholder="Enter Price (₹)"
              style={styles.input}
              value={price[req._id] || ""}
              onChange={(e) =>
                setPrice({
                  ...price,
                  [req._id]: e.target.value
                })
              }
            />

            {/* BUTTONS */}
            {req.status === "Pending" && (
              <div style={styles.buttonRow}>
                <button
                  style={styles.acceptBtn}
                  onClick={() => respondRequest(req._id, "Accepted")}
                >
                  Accept
                </button>

                <button
                  style={styles.rejectBtn}
                  onClick={() => respondRequest(req._id, "Rejected")}
                >
                  Reject
                </button>
              </div>
            )}

            {/* FEEDBACK */}
            {req.feedback && (
              <div style={styles.feedbackBox}>
                <div style={styles.rating}>
                  ⭐ {req.feedback.rating}/5
                </div>
                <div style={styles.comment}>
                  {req.feedback.comment}
                </div>
              </div>
            )}

          </div>
        ))}

      </div>
    </div>
  );
}

/* ================= MODERN CLEAN UI ================= */

const styles = {

  page: {
    background: "linear-gradient(180deg, #0b0f19, #0f172a)",
    minHeight: "100vh",
    color: "white",
    fontFamily: "Arial"
  },

  container: {
    maxWidth: "850px",
    margin: "auto",
    padding: "25px"
  },

  heading: {
    textAlign: "center",
    color: "#e5e7eb",
    marginBottom: "25px",
    fontSize: "22px",
    letterSpacing: "0.5px"
  },

  card: {
    position: "relative",
    background: "#111827",
    borderRadius: "14px",
    padding: "18px 18px 18px 22px",
    marginBottom: "14px",
    boxShadow: "0 6px 18px rgba(0,0,0,0.35)",
    transition: "0.2s",
    border: "1px solid #1f2937"
  },

  accent: {
    position: "absolute",
    left: "0",
    top: "0",
    bottom: "0",
    width: "4px",
    background: "#374151",
    borderRadius: "14px 0 0 14px"
  },

  header: {
    display: "flex",
    justifyContent: "space-between",
    alignItems: "center"
  },

  name: {
    margin: 0,
    color: "#f9fafb",
    fontSize: "16px"
  },

  badge: {
    background: "#1f2937",
    color: "#9ca3af",
    padding: "4px 10px",
    borderRadius: "6px",
    fontSize: "11px"
  },

  details: {
    marginTop: "8px",
    fontSize: "13px",
    color: "#cbd5e1",
    display: "flex",
    flexDirection: "column",
    gap: "4px"
  },

  input: {
    width: "100%",
    marginTop: "10px",
    padding: "12px",
    borderRadius: "8px",
    border: "1px solid #374151",
    background: "#0f172a",
    color: "white",
    outline: "none"
  },

  buttonRow: {
    display: "flex",
    gap: "10px",
    marginTop: "10px"
  },

  acceptBtn: {
    flex: 1,
    padding: "10px",
    background: "#16a34a",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  rejectBtn: {
    flex: 1,
    padding: "10px",
    background: "#dc2626",
    border: "none",
    borderRadius: "8px",
    color: "white",
    cursor: "pointer"
  },

  feedbackBox: {
    marginTop: "10px",
    padding: "10px",
    background: "#0f172a",
    border: "1px solid #374151",
    borderRadius: "8px"
  },

  rating: {
    color: "#facc15",
    fontWeight: "bold"
  },

  comment: {
    marginTop: "4px",
    color: "#9ca3af"
  },

  empty: {
    textAlign: "center",
    color: "#9ca3af"
  }
};
